// ============================================================================
// SENTINEL EXIT RULES ENGINE v1.1 — BUGFIX
// IRONCLAD v2.1 | METATRON v10.8
// FIXES: Breach count persistence via n8n variables API
//        Field name: reads stopAdjusted from VIX Scaling
// ============================================================================

const positions = $input.all().map(item => item.json);
const now = new Date();

// ── TIME CONTEXT ──────────────────────────────────────────────────────────────
const etOffset = -4; // EDT (Apr-Nov); change to -5 for EST
const etHour = (now.getUTCHours() + 24 + etOffset) % 24;
const etMinute = now.getUTCMinutes();
const etTimeDecimal = etHour + etMinute / 60;
const isMarketHours = etTimeDecimal >= 9.5 && etTimeDecimal < 16.0;
const isEODWindow = etTimeDecimal >= 15.75 && etTimeDecimal < 16.0;
const todayStr = now.toISOString().split('T')[0];

// ── BREACH COUNT PERSISTENCE (via n8n variables API) ─────────────────────────
let previousBreachCounts = {};
try {
  const bcResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://ashes2echoes.app.n8n.cloud/api/v1/variables',
    headers: { 'X-N8N-API-KEY': $vars['N8N_API_KEY'] },
    json: true
  });
  const vars = Array.isArray(bcResp) ? bcResp : (bcResp.data || []);
  for (const v of vars) {
    if (v.key === 'SENTINEL_BREACH_COUNTS') {
      try { previousBreachCounts = JSON.parse(v.value); } catch(e) {}
      break;
    }
  }
} catch(e) {
  // Can't read — start fresh
}

// ── VWAP DATA ─────────────────────────────────────────────────────────────────
let vwapData = {};
try {
  const mc = $('UW Data Pull').first().json;
  vwapData = mc.vwap || {};
} catch(e) {}

// ── PROCESS POSITIONS ─────────────────────────────────────────────────────────
const exitSignals = [];
const processedPositions = [];
const newBreachCounts = {};

for (const pos of positions) {
  const symbol = pos.symbol || '';
  const costBasis = parseFloat(pos.costBasis) || parseFloat(pos.pricePaid) || 0;
  const currentPrice = parseFloat(pos.currentPrice) || 0;
  const quantity = parseFloat(pos.quantity) || 0;
  const ring = pos.ring || 4;
  const track = pos.track || 2;

  // FIX: Read stopAdjusted from VIX Scaling (was effective_stop_threshold)
  const effectiveStop = parseFloat(pos.stopAdjusted) || parseFloat(pos.effective_stop_threshold) || 5;

  if (ring === 1) {
    processedPositions.push({ json: { ...pos, exit_signal: 'NONE', exit_rules: { skipped: true, reason: 'Ring 1' } } });
    continue;
  }
  if (costBasis <= 0 || currentPrice <= 0) {
    processedPositions.push({ json: { ...pos, exit_signal: 'NONE', exit_rules: { skipped: true, reason: 'Missing data' } } });
    continue;
  }

  const gainPct = ((currentPrice - costBasis) / costBasis) * 100;
  const gainDollar = (currentPrice - costBasis) * quantity;

  // ── STOP LOSS with Two-Check persistence ──────────────────────────────────
  const stopBreachRaw = gainPct < -effectiveStop;
  const prevCount = previousBreachCounts[symbol] || 0;
  const newCount = stopBreachRaw ? prevCount + 1 : 0;
  newBreachCounts[symbol] = newCount;
  const stopConfirmed = newCount >= 2;

  let exitSignal = 'NONE';
  let exitReason = '';
  let suggestedAction = 'HOLD';
  let exitQuantity = 0;

  if (stopConfirmed) {
    exitSignal = 'STOP_LOSS';
    exitReason = 'Stop confirmed: ' + gainPct.toFixed(2) + '% (threshold: -' + effectiveStop + '%) — scan ' + newCount;
    suggestedAction = 'SELL_ALL';
    exitQuantity = quantity;
  } else if (stopBreachRaw && newCount === 1) {
    exitSignal = 'STOP_LOSS_WARNING';
    exitReason = 'First breach at ' + gainPct.toFixed(2) + '%. Two-Check: next scan confirms.';
    suggestedAction = 'WATCH';
  }

  // ── PROFIT LOCKS ──────────────────────────────────────────────────────────
  if (gainPct >= 20.0 && !pos.profit_lock_2_executed && exitSignal === 'NONE') {
    exitSignal = 'PROFIT_LOCK_2';
    exitReason = '+' + gainPct.toFixed(2) + '% — sell 60%';
    suggestedAction = 'SELL_60_PCT';
    exitQuantity = Math.floor(quantity * 0.60);
  } else if (gainPct >= 10.0 && gainPct < 20.0 && !pos.profit_lock_1_executed && exitSignal === 'NONE') {
    exitSignal = 'PROFIT_LOCK_1';
    exitReason = '+' + gainPct.toFixed(2) + '% — sell 50%';
    suggestedAction = 'SELL_50_PCT';
    exitQuantity = Math.floor(quantity * 0.50);
  }

  // ── TIME STOP (Track 1 EOD) ───────────────────────────────────────────────
  if (track === 1 && isEODWindow && exitSignal === 'NONE') {
    if (gainPct > 0) {
      exitSignal = 'TIME_STOP_EOD';
      exitReason = 'Track 1 EOD exit +' + gainPct.toFixed(2) + '%';
      suggestedAction = 'SELL_ALL';
      exitQuantity = quantity;
    } else {
      exitSignal = 'TIME_STOP_EOD_LOSS';
      exitReason = 'Track 1 EOD ' + gainPct.toFixed(2) + '% — Principal decision';
      suggestedAction = 'REVIEW';
    }
  }

  if (exitSignal !== 'NONE') {
    exitSignals.push({ symbol, exitSignal, gainPct: parseFloat(gainPct.toFixed(2)), suggestedAction });
  }

  processedPositions.push({
    json: {
      ...pos,
      gain_pct: parseFloat(gainPct.toFixed(2)),
      gain_dollar: parseFloat(gainDollar.toFixed(2)),
      gainLossPercent: parseFloat(gainPct.toFixed(2)),
      gainLossDollars: parseFloat(gainDollar.toFixed(2)),
      effective_stop_threshold: effectiveStop,
      stop_breach_raw: stopBreachRaw,
      stop_breach_count: newCount,
      stop_breach_confirmed: stopConfirmed,
      exit_signal: exitSignal,
      exit_reason: exitReason,
      suggested_action: suggestedAction,
      exit_quantity: exitQuantity,
      recommended_action: suggestedAction,
      track, ring
    }
  });
}

// ── SAVE BREACH COUNTS BACK TO VARIABLE ───────────────────────────────────────
try {
  // Get variable ID
  const varsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://ashes2echoes.app.n8n.cloud/api/v1/variables',
    headers: { 'X-N8N-API-KEY': $vars['N8N_API_KEY'] },
