        body: JSON.stringify({ key: 'SENTINEL_BREACH_COUNTS', value: JSON.stringify(newBreachCounts) }),
        json: false
      });
      break;
    }
  }
} catch(e) {
  // Non-fatal — breach counts just won't persist this cycle
