      for (var p = 0; p < positionList.length; p++) {
        var pos = positionList[p];
        var prod = pos.Product || {};
        // Skip $0 market value positions (corporate actions, rights, warrants)
        if (!pos.marketValue || parseFloat(pos.marketValue) === 0) continue;
        items.push({ json: {
          symbol: prod.symbol || prod.securityType || '',
          currentPrice: pos.Quick ? pos.Quick.lastTrade : 0,
          pricePaid: pos.pricePaid || 0,
          costBasis: pos.pricePaid || (pos.totalCost ? (pos.totalCost / (pos.quantity || 1)) : 0),
          quantity: pos.quantity || 0,
          marketValue: pos.marketValue || 0,
          accountIdKey: raw.accountIdKey || acctPortfolio.accountId || '',
          accountName: raw.accountName || '',
          dateAcquired: pos.dateAcquired || null,
          totalCost: pos.totalCost || 0,
          totalGain: pos.totalGain || 0,
          totalGainPct: pos.totalGainPct || 0,
          positionType: pos.positionType || ''
        }});
      }
    }
  }
}

// Hardcoded Ring Assignment Lookup Table
const ringLookup = {
  // Ring 1: Core Income (no stops)
  'SGOV': 1,
  'JEPI': 1,
  'SCHD': 1,
  'SPHD': 1,
  'VOO': 1, // Ring 1: Core

  // Ring 2: Strategic Metals (10% base stop)
  'PSLV': 2,
  'IBIT': 2,
  'GLD': 2,
  'SIL': 2,
  'SLVR': 2,
  'CEF': 2,
  'PHYS': 2, // Ring 2: Strategic Metals

  // Ring 3: Defense/Healthcare (8.5% base stop)
  'PLTR': 3,
  'XLV': 3,
  'LMT': 3,
  'RTX': 3,
  'NOC': 3,
  'GD': 3,
  'LHX': 3, // Ring 3: Defense
  'ITA': 3, // Ring 3: Defense

  // Ring 4: Tactical/Event (5% base stop) - default for unlisted symbols
  'AG': 4,
  'HYMC': 4,
  'COPX': 4,
  'USO': 4,
  'XLE': 4, // Ring 4: Tactical
  'UFO': 4, // Ring 4: Tactical
  'RKLB': 4, // Ring 4: Tactical
  'MSFT': 4, // Ring 4: Tactical

  // Ring 5: Lottery (<$5 stocks, no stops) - determined by price
};

// Hardcoded Track Assignment Lookup Table
const trackLookup = {
  // Track 1: Daily Grind (income/core holdings)
  'SGOV': 1,
  'JEPI': 1,
  'SCHD': 1,
  'SPHD': 1,
  'PSLV': 1,
  'GLD': 1,
  'SIL': 1,
  'SLVR': 1,
  'CEF': 1,
  'XLV': 1,
  'VOO': 1, // Track 1: Daily Grind
  'PHYS': 1, // Track 1: Daily Grind

  // Track 2: Thesis (tactical/event plays)
  'PLTR': 2,
  'LMT': 2,
  'RTX': 2,
  'NOC': 2,
  'GD': 2,
  'AG': 2,
  'HYMC': 2,
  'COPX': 2,
  'IBIT': 2,
  'USO': 2,
  'LHX': 2, // Track 2: Thesis
  'ITA': 2, // Track 2: Thesis
  'XLE': 2, // Track 2: Thesis
  'UFO': 2, // Track 2: Thesis
  'RKLB': 2, // Track 2: Thesis
  'MSFT': 2 // Track 2: Thesis
};

// Base stop percentages by ring
const baseStopsByRing = {
  1: null,  // Ring 1: No stops
  2: 10,    // Ring 2: 10%
  3: 8.5,   // Ring 3: 8.5%
  4: 5,     // Ring 4: 5%
  5: null   // Ring 5: No stops (lottery)
};

// Get VIX value from Market Context Pull node (default 20 if unavailable)
let vixValue = 20;
let marketContext = {};
try {
  marketContext = $('Market Context Pull').first().json || {};
  if (marketContext && marketContext.market_data && marketContext.market_data.VIX) {
    vixValue = parseFloat(marketContext.market_data.VIX.lastPrice) || 20;
  }
} catch (e) {
  marketContext = {};
}

// Calculate VIX scaling adjustment
let vixScaling = 0;
if (vixValue > 25) {
  vixScaling = (vixValue - 20) * 0.5;
}
if (vixValue > 35) {
  vixScaling += 1;
}
// Cap max widening at 10%
vixScaling = Math.min(vixScaling, 10);

// Calculate total account value for position percentages
let totalAccountValue = 0;
for (const item of items) {
  if (item.json.marketValue) {
    totalAccountValue += parseFloat(item.json.marketValue) || 0;
  }
}

// Process each position
for (const item of items) {
  const position = item.json;

  const symbol = position.symbol || '';
  const currentPrice = parseFloat(position.currentPrice) || 0;
  const costBasis = parseFloat(position.pricePaid) || parseFloat(position.costBasis) || 1; // Avoid division by zero
  const qty = parseFloat(position.quantity) || parseFloat(position.qty) || 0;
  const marketValue = parseFloat(position.marketValue) || 0;
  const accountId = position.accountIdKey || position.accountId || '';
  const dateAcquired = position.dateAcquired || position.acquiredDate || null;

  // Determine ring (check price for Ring 5)
  let ring = ringLookup[symbol] || 4; // Default to Ring 4 (tactical)
  if (currentPrice > 0 && currentPrice < 5 && ring === 4) {
    ring = 5; // Lottery stock
  }

  // Determine track
  const track = trackLookup[symbol] || 2; // Default to Track 2 (thesis)

  // Calculate gain/loss percentage
  const gainLossPct = ((currentPrice - costBasis) / costBasis) * 100;

  // Get base stop threshold
  const baseStop = baseStopsByRing[ring];

  // Calculate VIX-adjusted stop
  let stopAdjusted = baseStop;
  if (baseStop !== null) {
    stopAdjusted = baseStop + vixScaling;
  }

  // Calculate stop price
  let stopPrice = null;
  if (stopAdjusted !== null) {
    stopPrice = costBasis * (1 - stopAdjusted / 100);
  }

  // Calculate stop distance (current price vs stop price)
  let stopDistance = null;
  if (stopPrice !== null) {
    stopDistance = ((currentPrice - stopPrice) / currentPrice) * 100;
  }

  // Check if stop is breached
  const stopBreached = stopAdjusted !== null && gainLossPct < -stopAdjusted;

  // Check if approaching stop (within 1% of stop)
  const stopWarning = stopAdjusted !== null && gainLossPct < -(stopAdjusted - 1) && !stopBreached;

  // Trim candidates
  const trimCandidate = gainLossPct >= 10;
  const strongTrimCandidate = gainLossPct >= 20;

  // Position percentage
  const positionPct = totalAccountValue > 0 ? (marketValue / totalAccountValue) * 100 : 0;
  const oversized = positionPct > 20;

  // Holding period tracking
  let holdingDays = null;
  let washSaleWindow = false;
  if (dateAcquired) {
    const acquired = new Date(dateAcquired);
    const now = new Date();
    holdingDays = Math.floor((now - acquired) / (1000 * 60 * 60 * 24));
    washSaleWindow = holdingDays < 31;
  }

  enrichedPositions.push({
    ...position,
    symbol,
    accountId,
    ring,
    track,
    qty,
    costBasis: parseFloat(costBasis.toFixed(2)),
    currentPrice: parseFloat(currentPrice.toFixed(2)),
    gainLossPct: parseFloat(gainLossPct.toFixed(2)),
    stopPrice: stopPrice !== null ? parseFloat(stopPrice.toFixed(2)) : null,
    stopAdjusted,
    vixScaling: parseFloat(vixScaling.toFixed(2)),
    vixValue: parseFloat(vixValue.toFixed(2)),
    stopDistance: stopDistance !== null ? parseFloat(stopDistance.toFixed(2)) : null,
    trimCandidate,
    strongTrimCandidate,
    stopWarning,
    stopBreached,
    holdingDays,
    washSaleWindow,
    positionPct: parseFloat(positionPct.toFixed(2)),
    oversized
  });
}

return enrichedPositions.map(pos => ({ json: pos }));

// Compliance Engine - IRONCLAD v2.1 Full Compliance Checks
const items = $input.all();
const positions = items.map(item => item.json);

// Hardcoded sector map
const sectorMap = {
  'AG': 'metals',
  'HYMC': 'metals',
  'SIL': 'metals',
  'PSLV': 'metals',
  'GLD': 'metals',
  'SLVR': 'metals',
  'COPX': 'metals',
  'PHYS': 'metals',
  'CEF': 'metals',
  'PLTR': 'tech',
  'MSFT': 'tech',
  'UFO': 'tech',
  'XLE': 'energy',
  'ITA': 'defense',
  'LHX': 'defense',
  'RTX': 'defense',
  'NOC': 'defense',
  'IBIT': 'crypto',
  'SGOV': 'core',
  'JEPI': 'core',
  'SCHD': 'core',
  'SPHD': 'core',
  'VOO': 'core',
  'XLV': 'healthcare',
  'RKLB': 'aerospace',
};

const failures = [];
let checksPassed = 0;
let checksFailed = 0;
const checksRun = 8;

// Calculate total portfolio value across all accounts
let totalPortfolioValue = 0;
for (const pos of positions) {
  totalPortfolioValue += parseFloat(pos.marketValue) || 0;
}

// CHECK 1: Position size limit (20% max per position)
let positionSizePass = true;
for (const pos of positions) {
  const positionPct = parseFloat(pos.positionPct) || 0;
  if (positionPct > 20) {
    positionSizePass = false;
    failures.push({
      check: 'position_size_limit',
      detail: `${pos.symbol} at ${positionPct.toFixed(2)}% exceeds 20% limit`,
      severity: 'FAIL',
      symbol: pos.symbol,
      accountId: pos.accountId
    });
  }
}
if (positionSizePass) checksPassed++; else checksFailed++;

// CHECK 2: Sector concentration limit (35% max per sector)
const sectorTotals = {};
for (const pos of positions) {
  const sector = sectorMap[pos.symbol] || 'other';
  const marketValue = parseFloat(pos.marketValue) || 0;
  sectorTotals[sector] = (sectorTotals[sector] || 0) + marketValue;
}

let sectorConcentrationPass = true;
for (const [sector, value] of Object.entries(sectorTotals)) {
  const sectorPct = totalPortfolioValue > 0 ? (value / totalPortfolioValue) * 100 : 0;
  if (sectorPct > 35 && sector !== 'other') {
    sectorConcentrationPass = false;
    failures.push({
      check: 'sector_concentration',
      detail: `${sector} sector at ${sectorPct.toFixed(2)}% exceeds 35% limit`,
      severity: 'WARNING',
      sector,
      sectorPct: parseFloat(sectorPct.toFixed(2))
    });
  }
}
if (sectorConcentrationPass) checksPassed++; else checksFailed++;

// CHECK 3: Risk per trade limit (1.5% max portfolio risk per position)
let riskPerTradePass = true;
for (const pos of positions) {
  const marketValue = parseFloat(pos.marketValue) || 0;
  const stopDistance = parseFloat(pos.stopDistance) || 0;
  const riskAmount = marketValue * (stopDistance / 100);
  const riskPct = totalPortfolioValue > 0 ? (riskAmount / totalPortfolioValue) * 100 : 0;

  if (riskPct > 1.5 && stopDistance > 0) {
    riskPerTradePass = false;
    failures.push({
      check: 'risk_per_trade',
      detail: `${pos.symbol} risk at ${riskPct.toFixed(2)}% exceeds 1.5% limit`,
      severity: 'FAIL',
      symbol: pos.symbol,
      riskPct: parseFloat(riskPct.toFixed(2))
    });
  }
}
if (riskPerTradePass) checksPassed++; else checksFailed++;

// CHECK 4: Same-day re-entry ban
// Transaction history not available from upstream - flag as UNABLE_TO_CHECK
failures.push({
  check: 'same_day_reentry',
  detail: 'Transaction history unavailable - unable to verify',
  severity: 'INFO'
});
checksPassed++; // Count as pass since we can't check

// CHECK 5: Wash sale detection
let washSalePass = true;
for (const pos of positions) {
  const washSaleWindow = pos.washSaleWindow || false;
  const washSaleRisk = pos.wash_sale_risk || false;

  if (washSaleRisk) {
    washSalePass = false;
    failures.push({
      check: 'wash_sale',
      detail: `${pos.symbol} flagged as WASH_SALE_RISK`,
      severity: 'WARNING',
      symbol: pos.symbol,
      washSaleDetails: pos.wash_sale_details
    });
  } else if (washSaleWindow) {
    failures.push({
      check: 'wash_sale',
      detail: `${pos.symbol} in wash sale window (CAUTION)`,
      severity: 'INFO',
      symbol: pos.symbol
    });
  }
}
if (washSalePass) checksPassed++; else checksFailed++;

// CHECK 6: Correlation Kill Switch check
let killSwitchStatus = 'INACTIVE';
let marketContext = {};
try { marketContext = $('Market Context Pull').first().json || {}; } catch(e) { marketContext = { vix_price: 20, dxy_direction: 'FLAT', yield_direction: 'FLAT' }; }
const vixValue = parseFloat(marketContext.vix_price) || 15;
const dxyDirection = marketContext.dxy_direction || 'FLAT';
const yieldDirection = marketContext.yield_direction || 'FLAT';

const metalsSectorValue = sectorTotals['metals'] || 0;
const metalsPct = totalPortfolioValue > 0 ? (metalsSectorValue / totalPortfolioValue) * 100 : 0;

if (vixValue > 35 && metalsPct > 25) {
  killSwitchStatus = 'KILL_SWITCH_WARNING';
  failures.push({
    check: 'kill_switch',
    detail: `VIX ${vixValue.toFixed(2)} + metals ${metalsPct.toFixed(2)}% triggers warning`,
    severity: 'WARNING'
  });
  checksFailed++;
} else if (dxyDirection === 'UP' && yieldDirection === 'UP') {
  killSwitchStatus = 'KILL_SWITCH_ACTIVE';
  failures.push({
    check: 'kill_switch',
    detail: `DXY UP + Yields UP = KILL_SWITCH_ACTIVE. Recommend 50% metals reduction`,
    severity: 'FAIL',
    recommendation: '50% metals reduction'
  });
  checksFailed++;
} else {
  checksPassed++;
}

// CHECK 7: Trim compliance
let trimCompliancePass = true;
for (const pos of positions) {
  const gainLossPct = parseFloat(pos.gainLossPct) || 0;
  const ring = pos.ring || 0;
  const track = pos.track || 0;

  // Check for trim overdue (gain > +10% not trimmed)
  if (gainLossPct > 10) {
    trimCompliancePass = false;
    failures.push({
      check: 'trim_compliance',
      detail: `${pos.symbol} gain ${gainLossPct.toFixed(2)}% - TRIM_OVERDUE`,
      severity: 'WARNING',
      symbol: pos.symbol,
      gainLossPct
    });
  }

  // Check Track 1 hold violation (gain > +5% not exited by EOD)
  if (track === 1 && gainLossPct > 5) {
    trimCompliancePass = false;
    failures.push({
      check: 'trim_compliance',
      detail: `${pos.symbol} Track 1 gain ${gainLossPct.toFixed(2)}% - TRACK1_HOLD_VIOLATION`,
      severity: 'WARNING',
      symbol: pos.symbol,
      gainLossPct
    });
  }
}
if (trimCompliancePass) checksPassed++; else checksFailed++;

// CHECK 8: 48-hour embargo check
let embargoStatus = 'CLEAR';
try {
  // Attempt to fetch last kill switch event from Supabase
  // For now, use placeholder - would need HTTP Request to Supabase
  const lastKillSwitchTimestamp = null; // Placeholder

  if (lastKillSwitchTimestamp) {
    const lastKillSwitch = new Date(lastKillSwitchTimestamp);
    const now = new Date();
    const hoursSinceKillSwitch = (now - lastKillSwitch) / (1000 * 60 * 60);

    if (hoursSinceKillSwitch < 48) {
      embargoStatus = 'ACTIVE';
      failures.push({
        check: 'embargo',
        detail: `48-hour embargo active (${(48 - hoursSinceKillSwitch).toFixed(1)} hours remaining)`,
        severity: 'WARNING'
      });
      checksFailed++;
    } else {
      checksPassed++;
    }
  } else {
    checksPassed++; // No recent kill switch
  }
} catch (e) {
  checksPassed++; // Unable to check, assume clear
}

// Determine overall compliance status
let complianceStatus = 'PASS';
if (checksFailed > 0) {
  const hasFailSeverity = failures.some(f => f.severity === 'FAIL');
  complianceStatus = hasFailSeverity ? 'FAIL' : 'WARNING';
}

// Add compliance flags to each position
const enrichedPositions = positions.map(pos => ({
  ...pos,
  compliance_checked: true,
  compliance_timestamp: new Date().toISOString()
}));

return [{
  json: {
    complianceStatus,
    checksRun,
    checksPassed,
    checksFailed,
    failures,
    positions: enrichedPositions,
    killSwitchStatus,
    embargoStatus,
    sectorBreakdown: Object.entries(sectorTotals).map(([sector, value]) => ({
      sector,
      value,
      percentage: totalPortfolioValue > 0 ? parseFloat(((value / totalPortfolioValue) * 100).toFixed(2)) : 0
    })),
    totalPortfolioValue,
    timestamp: new Date().toISOString()
  }
}];

let alertData = {};
try {
  alertData = $('Alert Escalation Engine').first().json || {};
} catch(e) {
  alertData = {};
}
const date = new Date().toISOString().split('T')[0];

const breached = alertData.breachedPositions || [];
const trims = alertData.trimCandidates || [];
const level = alertData.escalationLevel || 'NONE';
const killSwitch = alertData.killSwitchStatus || 'INACTIVE';
const compliance = alertData.complianceStatus || 'UNKNOWN';

let telegram_message = `<b>SENTINEL PORTFOLIO REPORT</b>\n`;
telegram_message += `<i>${date} | ${alertData.positionCount || 0} positions</i>\n\n`;
telegram_message += `Escalation: <b>${level}</b>\n`;
telegram_message += `Compliance: ${compliance}\n`;
telegram_message += `Kill Switch: ${killSwitch}\n\n`;
if (breached.length > 0) {
  telegram_message += `⚠️ Stop Breached: ${[...new Set(breached)].join(', ')}\n`;
}
if (trims.length > 0) {
  telegram_message += `✂️ Trim Candidates: ${trims.join(', ')}\n`;
}
if (breached.length === 0 && trims.length === 0) {
  telegram_message += `✅ No alerts`;
}

const githubData = {
  date,
  alert_level: alertData.alert_level,
  escalation_reason: alertData.escalation_reason,
  compliance_status: alertData.compliance_status,
  total_positions: alertData.total_positions,
  cash_pct: alertData.cash_pct,
  alerts: alertData.alerts || [],
  timestamp: alertData.timestamp
};

const base64Content = Buffer.from(JSON.stringify(githubData, null, 2)).toString('base64');

return [{
  json: {
    telegram_message,
    telegram_bot_token: 'REDACTED_BOT_TOKEN',
    github_json: githubData,
    base64_content: base64Content,
    date,
    // SHEETS STRUCTURED FIELDS
    report_date: date,
    escalation_level: level,
    compliance_status: compliance,
    kill_switch_status: killSwitch,
    breached_positions: [...new Set(breached)].join(', '),
    trim_candidates: trims.join(', '),
    alert_count: alertData.alertCount || 0,
    position_count: alertData.positionCount || 0,
    alert_level: alertData.alert_level
  }
}];

const errorMessage = $json.error?.message || 'Unknown error';
const errorDescription = $json.error?.description || '';
const errorName = $json.error?.name || 'Error';
const timestamp = new Date().toISOString();

const telegramMessage = `🚨 <b>SENTINEL ERROR ALERT</b>\n\n` +
  `<b>Error Type:</b> ${errorName}\n` +
  `<b>Message:</b> ${errorMessage}\n` +
  (errorDescription ? `<b>Details:</b> ${errorDescription}\n` : '') +
  `\n<i>Timestamp: ${timestamp}</i>`;

return [{
  json: {
    error_message: telegramMessage,
    error_details: {
      name: errorName,
      message: errorMessage,
      description: errorDescription,
      timestamp
    }
  }
}]

