// Wash Sale Tracker - Monitors positions against wash sale restrictions
const items = $input.all();
const positions = items.map(item => item.json);

// Hardcoded wash sale restrictions
const washSaleRestrictions = [
  {
    symbol: 'SLVR',
    accountIdKey: null, // Applies to all accounts
    sellDate: '2026-03-13',
    restrictedUntil: '2026-04-13'
  },
  {
    symbol: 'PSLV',
    accountIdKey: '-4898',
    sellDate: '2026-03-13',
    restrictedUntil: '2026-04-13'
  },
  {
    symbol: 'COPX',
    accountIdKey: '-6685',
    sellDate: '2026-03-13',
    restrictedUntil: '2026-04-13'
  }
];

const today = new Date();
const enrichedPositions = [];

// Check each position against wash sale restrictions
for (const position of positions) {
  const symbol = position.symbol || '';
  const accountIdKey = position.accountIdKey || '';

  let washSaleRisk = false;
  let restrictionDetails = null;

  // Check if position matches any restriction
  for (const restriction of washSaleRestrictions) {
    const symbolMatch = restriction.symbol === symbol;
    const accountMatch = restriction.accountIdKey === null || restriction.accountIdKey === accountIdKey;
    const restrictedUntilDate = new Date(restriction.restrictedUntil);
    const stillRestricted = today <= restrictedUntilDate;

    if (symbolMatch && accountMatch && stillRestricted) {
      washSaleRisk = true;
      restrictionDetails = {
        sellDate: restriction.sellDate,
        restrictedUntil: restriction.restrictedUntil,
        daysRemaining: Math.ceil((restrictedUntilDate - today) / (1000 * 60 * 60 * 24))
      };
      break;
    }
  }

  // Add wash sale risk flag to position
  const enrichedPosition = {
    ...position,
    wash_sale_risk: washSaleRisk,
    wash_sale_details: restrictionDetails
  };

  enrichedPositions.push(enrichedPosition);
}

// Return all positions with wash_sale_risk flags added
return enrichedPositions.map(pos => ({ json: pos }));

// Alert Escalation Engine - Complete replacement
let complianceData = {};
try {
  complianceData = $('Compliance Engine').first().json;
} catch(e) {
  const inputItems = $input.all().map(i => i.json);
  complianceData = inputItems.find(i => i.complianceStatus) || {};
}

const positions = $input.all().map(item => item.json);
const failures = complianceData.failures || [];
const killSwitchStatus = complianceData.killSwitchStatus || 'INACTIVE';

// Determine escalation level
let escalationLevel = 'NONE';
let alerts = [];

const failCount = failures.filter(f => f.severity === 'FAIL').length;
const warnCount = failures.filter(f => f.severity === 'WARNING').length;

if (killSwitchStatus === 'KILL_SWITCH_ACTIVE' || failCount >= 3) {
  escalationLevel = 'CRITICAL';
} else if (failCount >= 1) {
  escalationLevel = 'HIGH';
} else if (warnCount >= 2) {
  escalationLevel = 'MEDIUM';
} else if (warnCount >= 1) {
  escalationLevel = 'LOW';
}

// Build alert messages
for (const f of failures) {
  alerts.push({
    check: f.check,
    detail: f.detail,
    severity: f.severity,
    symbol: f.symbol || null
  });
}

// Build position summary for alerting
const breachedPositions = positions.filter(p => p.stopBreached === true);
const trimCandidates = positions.filter(p => p.trimCandidate === true);

return [{
  json: {
    escalationLevel,
    alertCount: alerts.length,
    alerts,
    killSwitchStatus,
    complianceStatus: complianceData.complianceStatus || 'UNKNOWN',
    breachedPositions: breachedPositions.map(p => p.symbol),
    trimCandidates: trimCandidates.map(p => p.symbol),
    positionCount: positions.length,
    timestamp: new Date().toISOString()
  }
}];

const currentPositions = $input.all().map(item => item.json);
const changes = [];

// In production, this would fetch previous positions from Supabase or workflow static variable
// For now, we'll use a placeholder that assumes this is the first run
const previousPositions = []; // Placeholder - would fetch from Supabase

if (previousPositions.length === 0) {
  // First run - all positions are new
  for (const pos of currentPositions) {
    if (pos.symbol !== 'CASH') {
      changes.push({
        type: 'NEW',
        symbol: pos.symbol,
        accountName: pos.accountName,
        quantity: pos.quantity,
        currentPrice: pos.currentPrice,
        details: `New position: ${pos.quantity} shares at $${pos.currentPrice}`
      });
    }
  }
} else {
  // Compare current to previous
  const prevMap = new Map(previousPositions.map(p => [`${p.symbol}-${p.accountIdKey}`, p]));
  const currMap = new Map(currentPositions.map(p => [`${p.symbol}-${p.accountIdKey}`, p]));

  // Check for new positions
  for (const [key, curr] of currMap) {
    if (!prevMap.has(key) && curr.symbol !== 'CASH') {
      changes.push({
        type: 'NEW',
        symbol: curr.symbol,
        accountName: curr.accountName,
        quantity: curr.quantity,
        details: `New position opened: ${curr.quantity} shares`
      });
    }
  }

  // Check for closed positions
  for (const [key, prev] of prevMap) {
    if (!currMap.has(key) && prev.symbol !== 'CASH') {
      changes.push({
        type: 'CLOSED',
        symbol: prev.symbol,
        accountName: prev.accountName,
        quantity: prev.quantity,
        details: `Position closed: ${prev.quantity} shares sold`
      });
    }
  }

  // Check for quantity and price changes
  for (const [key, curr] of currMap) {
    const prev = prevMap.get(key);
    if (prev && curr.symbol !== 'CASH') {
      // Quantity change
      if (curr.quantity !== prev.quantity) {
        const diff = curr.quantity - prev.quantity;
        changes.push({
          type: diff > 0 ? 'INCREASED' : 'DECREASED',
          symbol: curr.symbol,
          accountName: curr.accountName,
          quantity: Math.abs(diff),
          details: `${diff > 0 ? 'Added' : 'Reduced'} ${Math.abs(diff)} shares`
        });
      }

      // Price movement >3%
      const pricePctChange = ((curr.currentPrice - prev.currentPrice) / prev.currentPrice) * 100;
      if (Math.abs(pricePctChange) > 3) {
        changes.push({
          type: 'PRICE_MOVE',
          symbol: curr.symbol,
          accountName: curr.accountName,
          priceChange: pricePctChange,
          details: `Price ${pricePctChange > 0 ? 'up' : 'down'} ${Math.abs(pricePctChange).toFixed(2)}%`
        });
      }
    }
  }
}

