  txn.action === 'SELL' && 
  txn.gainLoss !== null && 
  txn.gainLoss < 0
);

// Check each sell for wash sale violations
for (const sell of sellsWithLoss) {
  const sellDate = new Date(sell.date);
  const symbol = sell.symbol;
  const accountId = sell.accountId;

  // Check for buys within 30 days before or after
  const washSaleBuys = transactions.filter(txn => {
    if (txn.action !== 'BUY' || txn.symbol !== symbol) return false;

    const buyDate = new Date(txn.date);
    const daysDiff = Math.abs((buyDate - sellDate) / (1000 * 60 * 60 * 24));

    return daysDiff <= 30;
  });

  if (washSaleBuys.length > 0) {
    // Wash sale violation detected
    for (const buy of washSaleBuys) {
      washSaleViolations.push({
        symbol,
        accountId,
        wash_sale_violation: true,
        sell_date: sell.date,
        sell_price: sell.price,
        sell_qty: sell.qty,
        disallowed_loss: sell.gainLoss,
        buy_date: buy.date,
        buy_price: buy.price,
        buy_qty: buy.qty,
        days_between: Math.abs((new Date(buy.date) - sellDate) / (1000 * 60 * 60 * 24)),
        detected_at: new Date().toISOString(),
        alert_message: `🚨 WASH SALE VIOLATION: ${symbol} sold at loss on ${sell.date}, repurchased on ${buy.date} (within 30 days). Disallowed loss: $${Math.abs(sell.gainLoss).toFixed(2)}`
      });
    }
  }
}

