const crypto = require('crypto');

const CONSUMER_KEY = $vars['ETRADE_CONSUMER_KEY'];
const CONSUMER_SECRET = $vars['ETRADE_CONSUMER_SECRET'];
const ACCESS_TOKEN = $vars['ETRADE_ACCESS_TOKEN'];
const ACCESS_TOKEN_SECRET = $vars['ETRADE_ACCESS_TOKEN_SECRET'];

function encode(s) {
  return encodeURIComponent(String(s))
    .split('!').join('%21')
    .split("'").join('%27')
    .split('(').join('%28')
    .split(')').join('%29')
    .split('*').join('%2A');
}

function buildAuthHeader(method, baseUrl, qpKeys, qpVals) {
  const timestamp = Math.floor(Date.now() / 1000).toString();
  const nonce = Math.random().toString(36).substring(2) + Math.random().toString(36).substring(2);

  const oKeys = ['oauth_consumer_key','oauth_nonce','oauth_signature_method','oauth_timestamp','oauth_token','oauth_version'];
  const oVals = [CONSUMER_KEY, nonce, 'HMAC-SHA1', timestamp, ACCESS_TOKEN, '1.0'];

  const allKeys = oKeys.concat(qpKeys);
  const allVals = oVals.concat(qpVals);

  const pairs = [];
  for (let i = 0; i < allKeys.length; i++) {
    pairs.push(encode(allKeys[i]) + '=' + encode(allVals[i]));
  }
  pairs.sort();

  const sortedParams = pairs.join('&');
  const signatureBase = method + '&' + encode(baseUrl) + '&' + encode(sortedParams);
  const signingKey = encode(CONSUMER_SECRET) + '&' + encode(ACCESS_TOKEN_SECRET);

  const signature = crypto.createHmac('sha1', signingKey).update(signatureBase).digest('base64');

  const hKeys = oKeys.concat(['oauth_signature']);
  const hVals = oVals.concat([signature]);

  const headerParts = [];
  for (let i = 0; i < hKeys.length; i++) {
    headerParts.push(hKeys[i] + '="' + encode(hVals[i]) + '"');
  }

  return 'OAuth realm="",' + headerParts.join(',');
}

