// GitHub Archive — GET-then-PUT pattern
const GITHUB_TOKEN = 'REDACTED_GH_TOKEN';
const REPO = 'Barefootservants2/AIORA';
const input = $input.first().json;
const filename = input.snapshot_filename || new Date().toISOString().split('T')[0] + '.json';
const filePath = 'SENTINEL/snapshots/' + filename;
const apiUrl = 'https://api.github.com/repos/' + REPO + '/contents/' + filePath;

// Content to upload
const content = input.base64_content || Buffer.from(JSON.stringify(input, null, 2)).toString('base64');

const headers = {
  'Authorization': 'token ' + GITHUB_TOKEN,
  'Accept': 'application/vnd.github.v3+json',
  'User-Agent': 'SENTINEL-n8n'
};

// Step 1: GET existing file SHA (if file exists)
let sha = null;
try {
  const existing = await this.helpers.httpRequest({
    method: 'GET',
    url: apiUrl,
    headers: headers,
    json: true
  });
  sha = existing.sha;
} catch (e) {
  // 404 = new file, no SHA needed
  sha = null;
}

// Step 2: PUT with SHA (update) or without (create)
const body = {
  message: 'SENTINEL snapshot ' + new Date().toISOString(),
  content: content
};
if (sha) {
  body.sha = sha;
}

try {
  const result = await this.helpers.httpRequest({
    method: 'PUT',
    url: apiUrl,
    headers: headers,
    body: body,
    json: true
  });
  return [{ json: { github_status: 'SUCCESS', path: filePath, sha: result.content.sha } }];
} catch (error) {
  return [{ json: { github_status: 'FAILED', error: error.message, path: filePath } }];
}

